function Logo({ size = 30 }) {
  return (
    <img
      src={AIRIS_LOGO_SRC}
      alt="Airis"
      width={size}
      height={size}
      style={{ width: size, height: size, objectFit: 'contain', display: 'block', flexShrink: 0 }}
      draggable={false}
    />
  )
}

function Nav({ current, navigate }) {
  const [scrolled, setScrolled] = useState(false)
  const [menuOpen, setMenuOpen] = useState(false)

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20)
    window.addEventListener('scroll', onScroll)
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  const links = [
    { label: 'Home', page: 'home' },
    { label: 'Features', page: 'features' },
    { label: 'Technology', page: 'technology' },
    { label: 'About', page: 'about' },
    { label: 'FAQ', page: 'faq' },
    { label: 'Contact', page: 'contact' },
  ]

  return (
    <nav style={{
      position: 'fixed', top: 0, left: 0, right: 0, zIndex: 100,
      background: scrolled ? 'rgba(6,13,26,0.78)' : 'rgba(6,13,26,0.3)',
      backdropFilter: 'blur(18px)', WebkitBackdropFilter: 'blur(18px)',
      borderBottom: '1px solid ' + (scrolled ? 'var(--hair)' : 'transparent'),
      transition: 'all .3s ease',
    }}>
      <div className="wrap" style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', height: 68 }}>
        <button onClick={() => navigate('home')} style={{ display: 'flex', alignItems: 'center', gap: 10, background: 'none', border: 'none', cursor: 'pointer' }}>
          <Logo />
          <span className="df" style={{ fontWeight: 700, fontSize: 18, color: '#fff', letterSpacing: '-0.02em' }}>AIRIS</span>
        </button>

        <div className="hidden md:flex" style={{ alignItems: 'center', gap: 30 }}>
          {links.map(l => (
            <button key={l.page} onClick={() => navigate(l.page)} className={`nav-link ${current === l.page ? 'active' : ''}`} style={{ background: 'none', border: 'none', cursor: 'pointer' }}>
              {l.label}
            </button>
          ))}
        </div>

        <div className="hidden md:flex">
          <button className="btn btn-primary" style={{ padding: '10px 22px', fontSize: 13 }} onClick={() => navigate('waitlist')}>
            Join Waitlist <ArrowRight size={14} />
          </button>
        </div>

        <button className="md:hidden" style={{ background: 'none', border: 'none', color: '#fff', cursor: 'pointer' }} onClick={() => setMenuOpen(!menuOpen)}>
          {menuOpen ? <X size={22} /> : <Menu size={22} />}
        </button>
      </div>

      {menuOpen && (
        <div className="md:hidden fade-in" style={{ background: 'rgba(6,13,26,0.97)', borderTop: '1px solid var(--hair)', padding: '10px 24px 24px' }}>
          {links.map(l => (
            <button key={l.page} onClick={() => { navigate(l.page); setMenuOpen(false) }}
              className={`nav-link ${current === l.page ? 'active' : ''}`}
              style={{ display: 'block', width: '100%', textAlign: 'left', padding: '14px 0', borderBottom: '1px solid var(--hair)', background: 'none', border: 'none', fontSize: 15 }}>
              {l.label}
            </button>
          ))}
          <button className="btn btn-primary" style={{ width: '100%', marginTop: 16, padding: 14 }} onClick={() => { navigate('waitlist'); setMenuOpen(false) }}>
            Join Waitlist
          </button>
        </div>
      )}
    </nav>
  )
}

