// ============================================================================
// FAQ PAGE
// ============================================================================
function FAQPage() {
  const [search, setSearch] = useState('')
  const [activeCategory, setActiveCategory] = useState('All')
  const [openItem, setOpenItem] = useState(null)
  const categories = ['All', 'Eye Safety', 'Technology', 'Pricing', 'Compatibility', 'Shipping']
  const allFaqs = [
    { q: 'Is Airis safe to wear?', a: 'Airis has completed clinical trials across 18 countries with 4,000+ participants, ISO 13485 certified materials, and FDA Breakthrough Device Designation. Zero adverse events in Phase III.', category: 'Eye Safety' },
    { q: 'Can I wear Airis while sleeping?', a: 'No — daily wear only, up to 16 hours. Remove and place in the charging case each night.', category: 'Eye Safety' },
    { q: 'Are the electronics safe near my eye?', a: 'All components run well below international safety thresholds (IEC 62209) — RF emission is 10,000× below the safety limit.', category: 'Eye Safety' },
    { q: 'How does the on-lens AI processor work?', a: 'A custom 5nm RISC-V chip computes vision correction at 120Hz and health monitoring at 60Hz — entirely on-device, no raw biometric data leaves the lens.', category: 'Technology' },
    { q: 'Does it work with my smartphone?', a: 'Any Bluetooth 5.0+ phone on iOS 16+ or Android 12+. The companion app covers iPhone, Samsung, Pixel, and all qualifying Android devices.', category: 'Compatibility' },
    { q: 'Can Airis replace my current prescription?', a: 'Yes — a wide prescription range plus adaptive optics beyond fixed powers means many users no longer need glasses for daily activity.', category: 'Eye Safety' },
    { q: 'How much will Airis cost?', a: 'Pricing isn\u2019t final. Based on comparable devices we expect a starter kit around $299\u2013$499, with monitoring from $19/month. Early access gets 30% off.', category: 'Pricing' },
    { q: 'Is insurance coverage expected?', a: 'We\u2019re working with major US and EU insurers on reimbursement codes. HSA/FSA coverage may be available for diagnosed glaucoma or diabetes patients at launch.', category: 'Pricing' },
    { q: 'When will Airis ship?', a: 'Commercial launch is planned for Q2 2027 in the US, EU, UK, Japan, and Australia — waitlist members get priority.', category: 'Shipping' },
    { q: 'Will Airis work with Android?', a: 'Yes, full support for Android 12+ with Bluetooth 5.0. Available on Google Play and the Galaxy Store.', category: 'Compatibility' },
  ]
  const filtered = allFaqs.filter(f => (activeCategory === 'All' || f.category === activeCategory) && (search === '' || f.q.toLowerCase().includes(search.toLowerCase()) || f.a.toLowerCase().includes(search.toLowerCase())))

  return (
    <div>
      <PageHero eyebrow="FAQ" title={<>Frequently asked <span className="grad-text">questions</span></>} sub="Everything you need to know about Airis.">
        <div style={{ position: 'relative', maxWidth: 420, margin: '32px auto 0' }}>
          <Search size={17} color="var(--muted-2)" style={{ position: 'absolute', left: 16, top: '50%', transform: 'translateY(-50%)' }} />
          <input type="text" placeholder="Search questions..." value={search} onChange={e => setSearch(e.target.value)}
            style={{ width: '100%', padding: '13px 16px 13px 44px', borderRadius: 12, background: 'rgba(255,255,255,0.07)', border: '1px solid var(--glass-border)', color: '#fff', fontSize: 14, outline: 'none' }} />
        </div>
      </PageHero>

      <div className="wrap section" style={{ maxWidth: 700, paddingTop: 20 }}>
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8, justifyContent: 'center', marginBottom: 44 }}>
          {categories.map(c => (
            <button key={c} onClick={() => setActiveCategory(c)}
              style={{ padding: '8px 16px', borderRadius: 999, fontSize: 13, fontWeight: 500, cursor: 'pointer', background: activeCategory === c ? 'var(--blue)' : 'rgba(255,255,255,0.05)', color: activeCategory === c ? '#fff' : 'var(--muted)', border: '1px solid ' + (activeCategory === c ? 'var(--blue)' : 'var(--glass-border)') }}>
              {c}
            </button>
          ))}
        </div>

        {filtered.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '60px 0', color: 'var(--muted-2)' }}>
            <Search size={32} style={{ margin: '0 auto 12px' }} />
            <p>No questions found for &ldquo;{search}&rdquo;</p>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            {filtered.map((item, i) => (
              <div key={i} className="card" style={{ overflow: 'hidden' }}>
                <button onClick={() => setOpenItem(openItem === i ? null : i)} style={{ width: '100%', padding: '18px 22px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: 'none', border: 'none', cursor: 'pointer', textAlign: 'left', gap: 14 }}>
                  <div>
                    <span className="mono" style={{ fontSize: 9.5, fontWeight: 600, color: 'var(--cyan)', background: 'rgba(56,189,248,0.1)', padding: '3px 8px', borderRadius: 6, marginRight: 10, letterSpacing: '0.04em' }}>{item.category.toUpperCase()}</span>
                    <span className="df" style={{ fontWeight: 600, fontSize: 14.5, color: '#fff' }}>{item.q}</span>
                  </div>
                  <ChevronDown size={16} color="var(--cyan)" style={{ transform: openItem === i ? 'rotate(180deg)' : 'none', transition: 'transform .25s', flexShrink: 0 }} />
                </button>
                <div className="accordion-content" style={{ maxHeight: openItem === i ? 260 : 0, opacity: openItem === i ? 1 : 0 }}>
                  <p style={{ padding: '0 22px 20px', fontSize: 13.5, color: 'var(--muted)', lineHeight: 1.6 }}>{item.a}</p>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

