function ContactPage() {
  const [form, setForm] = useState({ name: '', email: '', message: '' })
  const [sent, setSent] = useState(false)
  const handleSubmit = (e) => { e.preventDefault(); setSent(true) }

  const inputStyle = { width: '100%', padding: '13px 16px', borderRadius: 12, background: 'rgba(255,255,255,0.05)', border: '1px solid var(--glass-border)', color: '#fff', fontSize: 14, outline: 'none', fontFamily: 'inherit' }

  return (
    <div>
      <PageHero eyebrow="Contact" title={<>Get in <span className="grad-text">touch</span></>} sub="Questions, press enquiries, or partnership opportunities — we'd love to hear from you." />

      <div className="wrap section grid md:grid-cols-2" style={{ paddingTop: 30, gap: 50 }}>
          <Reveal>
            <div>
              <h2 className="df" style={{ fontWeight: 700, fontSize: 21, color: '#fff', marginBottom: 22 }}>Send us a message</h2>
              {sent ? (
                <div className="glass-panel fade-in" style={{ borderRadius: 20, padding: 40, textAlign: 'center' }}>
                  <CheckCircle2 size={36} color="var(--emerald)" style={{ margin: '0 auto 14px' }} />
                  <div className="df" style={{ fontWeight: 700, fontSize: 18, color: '#fff', marginBottom: 6 }}>Message sent</div>
                  <p style={{ fontSize: 13.5, color: 'var(--muted)' }}>We'll reply to {form.email} within 24 hours.</p>
                </div>
              ) : (
                <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: 18 }}>
                  <div>
                    <label style={{ display: 'block', fontSize: 12.5, color: 'var(--muted)', marginBottom: 7 }}>Full Name</label>
                    <input required style={inputStyle} placeholder="Jane Smith" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} />
                  </div>
                  <div>
                    <label style={{ display: 'block', fontSize: 12.5, color: 'var(--muted)', marginBottom: 7 }}>Email Address</label>
                    <input required type="email" style={inputStyle} placeholder="jane@example.com" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} />
                  </div>
                  <div>
                    <label style={{ display: 'block', fontSize: 12.5, color: 'var(--muted)', marginBottom: 7 }}>Message</label>
                    <textarea required rows={5} style={{ ...inputStyle, resize: 'none' }} placeholder="Tell us about your inquiry..." value={form.message} onChange={e => setForm({ ...form, message: e.target.value })} />
                  </div>
                  <button type="submit" className="btn btn-primary" style={{ width: '100%', padding: 14 }}>Send Message</button>
                </form>
              )}
            </div>
          </Reveal>

          <Reveal delay={100}>
            <div>
              <h2 className="df" style={{ fontWeight: 700, fontSize: 21, color: '#fff', marginBottom: 22 }}>Contact information</h2>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 20, marginBottom: 30 }}>
                {[[MapPin, 'Address', 'Siam University, Global Academy, 38 Phet Kasem Rd, Bang Wa, Phasi Charoen, Bangkok 10160, Thailand'], [Mail, 'Email', '1234@ga.edu'], [Phone, 'Phone', '+66 06123456'], [Clock, 'Hours', 'Mon\u2013Fri, 9am\u20136pm']].map(([Icon, label, value]) => (
                  <div key={label} style={{ display: 'flex', gap: 14, alignItems: 'flex-start' }}>
                    <div style={{ width: 36, height: 36, borderRadius: 10, background: 'rgba(56,189,248,0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}><Icon size={16} color="var(--cyan)" /></div>
                    <div>
                      <div className="mono" style={{ fontSize: 10, color: 'var(--muted-2)', letterSpacing: '0.05em', marginBottom: 2 }}>{label.toUpperCase()}</div>
                      <div style={{ fontSize: 13.5, color: '#dbe6f5', lineHeight: 1.5 }}>{value}</div>
                    </div>
                  </div>
                ))}
              </div>
              <div className="glass-panel" style={{ borderRadius: 18, height: 200, display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative', overflow: 'hidden' }}>
                <ParticleField density={25} />
                <div style={{ textAlign: 'center', position: 'relative', zIndex: 2 }}>
                  <MapPin size={26} color="var(--cyan)" style={{ margin: '0 auto 8px' }} />
                  <div className="df" style={{ fontSize: 14, fontWeight: 600, color: '#fff' }}>Bangkok, Thailand</div>
                  <div className="mono" style={{ fontSize: 10.5, color: 'var(--muted-2)', marginTop: 3 }}>GLOBAL ACADEMY</div>
                </div>
              </div>
              <div style={{ display: 'flex', gap: 10, marginTop: 20 }}>
                {[Twitter, Linkedin, Youtube, Facebook].map((Icon, i) => (
                  <button key={i} style={{ flex: 1, padding: '12px 0', borderRadius: 12, background: 'rgba(255,255,255,0.04)', border: '1px solid var(--glass-border)', color: 'var(--muted)', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Icon size={15} /></button>
                ))}
              </div>
            </div>
          </Reveal>
      </div>
    </div>
  )
}

// ============================================================================
// WAITLIST PAGE
// ============================================================================
function WaitlistPage({ navigate }) {
  const [form, setForm] = useState({ firstName: '', lastName: '', email: '', country: '', occupation: '', agreed: false })
  const [errors, setErrors] = useState({})
  const [loading, setLoading] = useState(false)
  const countries = ['United States', 'United Kingdom', 'Canada', 'Australia', 'Germany', 'France', 'Japan', 'Singapore', 'Other']
  const occupations = ['Healthcare Professional', 'Patient / Individual', 'Researcher / Academic', 'Industry / Tech', 'Investor', 'Media / Press', 'Other']

  const validate = () => {
    const e = {}
    if (!form.firstName.trim()) e.firstName = 'Required'
    if (!form.lastName.trim()) e.lastName = 'Required'
    if (!form.email.includes('@')) e.email = 'Enter a valid email'
    if (!form.country) e.country = 'Select a country'
    if (!form.occupation) e.occupation = 'Select an occupation'
    if (!form.agreed) e.agreed = 'You must agree to the Privacy Policy'
    return e
  }

  const handleSubmit = (e) => {
    e.preventDefault()
    const errs = validate()
    if (Object.keys(errs).length > 0) { setErrors(errs); return }
    setLoading(true)
    setTimeout(() => { setLoading(false); navigate('success') }, 1200)
  }

  const inputStyle = (key) => ({ width: '100%', padding: '12px 15px', borderRadius: 11, background: 'rgba(255,255,255,0.05)', border: '1px solid ' + (errors[key] ? 'var(--red)' : 'var(--glass-border)'), color: '#fff', fontSize: 13.5, outline: 'none', fontFamily: 'inherit' })

  return (
    <div style={{ minHeight: '100vh' }}>
      <PageHero eyebrow="Limited Early Access — 18,247 on waitlist" title={<>Join the Airis <span className="grad-text">early access program</span></>} sub="Members receive 30% off retail price, priority shipping, and exclusive beta features." />

      <div className="wrap" style={{ maxWidth: 520, padding: '10px 24px 100px' }}>
        <Reveal>
          <div className="glass-panel" style={{ borderRadius: 24, padding: 36 }}>
            <h2 className="df" style={{ fontWeight: 700, fontSize: 18, color: '#fff', marginBottom: 22 }}>Application Form</h2>
            <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
                <div>
                  <label style={{ display: 'block', fontSize: 12, color: 'var(--muted)', marginBottom: 6 }}>First Name</label>
                  <input placeholder="Jane" style={inputStyle('firstName')} value={form.firstName} onChange={e => setForm({ ...form, firstName: e.target.value })} />
                  {errors.firstName && <p style={{ fontSize: 11, color: 'var(--red)', marginTop: 5 }}>{errors.firstName}</p>}
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: 12, color: 'var(--muted)', marginBottom: 6 }}>Last Name</label>
                  <input placeholder="Smith" style={inputStyle('lastName')} value={form.lastName} onChange={e => setForm({ ...form, lastName: e.target.value })} />
                  {errors.lastName && <p style={{ fontSize: 11, color: 'var(--red)', marginTop: 5 }}>{errors.lastName}</p>}
                </div>
              </div>
              <div>
                <label style={{ display: 'block', fontSize: 12, color: 'var(--muted)', marginBottom: 6 }}>Email Address</label>
                <input placeholder="jane@example.com" style={inputStyle('email')} value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} />
                {errors.email && <p style={{ fontSize: 11, color: 'var(--red)', marginTop: 5 }}>{errors.email}</p>}
              </div>
              <div>
                <label style={{ display: 'block', fontSize: 12, color: 'var(--muted)', marginBottom: 6 }}>Country</label>
                <select style={{ ...inputStyle('country'), cursor: 'pointer' }} value={form.country} onChange={e => setForm({ ...form, country: e.target.value })}>
                  <option value="">Select your country</option>
                  {countries.map(c => <option key={c} value={c} style={{ background: '#0F2544' }}>{c}</option>)}
                </select>
                {errors.country && <p style={{ fontSize: 11, color: 'var(--red)', marginTop: 5 }}>{errors.country}</p>}
              </div>
              <div>
                <label style={{ display: 'block', fontSize: 12, color: 'var(--muted)', marginBottom: 6 }}>Occupation</label>
                <select style={{ ...inputStyle('occupation'), cursor: 'pointer' }} value={form.occupation} onChange={e => setForm({ ...form, occupation: e.target.value })}>
                  <option value="">Select your occupation</option>
                  {occupations.map(o => <option key={o} value={o} style={{ background: '#0F2544' }}>{o}</option>)}
                </select>
                {errors.occupation && <p style={{ fontSize: 11, color: 'var(--red)', marginTop: 5 }}>{errors.occupation}</p>}
              </div>
              <div>
                <label style={{ display: 'flex', gap: 10, cursor: 'pointer', alignItems: 'flex-start' }}>
                  <div onClick={() => setForm(f => ({ ...f, agreed: !f.agreed }))}
                    style={{ width: 19, height: 19, borderRadius: 5, flexShrink: 0, marginTop: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', background: form.agreed ? 'var(--blue)' : 'transparent', border: '1.5px solid ' + (errors.agreed ? 'var(--red)' : form.agreed ? 'var(--blue)' : 'var(--glass-border)') }}>
                    {form.agreed && <CheckCircle2 size={13} color="#fff" />}
                  </div>
                  <span style={{ fontSize: 12.5, color: 'var(--muted)', lineHeight: 1.5 }}>I agree to the <span style={{ color: 'var(--cyan)' }}>Privacy Policy</span> and consent to being contacted about Airis products and updates.</span>
                </label>
                {errors.agreed && <p style={{ fontSize: 11, color: 'var(--red)', marginTop: 5 }}>{errors.agreed}</p>}
              </div>
              <button type="submit" className="btn btn-primary" style={{ width: '100%', padding: 14, marginTop: 4, opacity: loading ? 0.75 : 1 }}>
                {loading ? 'Submitting...' : <>Join Waitlist <ArrowRight size={14} /></>}
              </button>
            </form>
            <p style={{ fontSize: 11, color: 'var(--muted-2)', textAlign: 'center', marginTop: 16 }}>No spam, ever. Unsubscribe at any time.</p>
          </div>
        </Reveal>
      </div>
    </div>
  )
}

// ============================================================================
// SUCCESS PAGE
// ============================================================================
function SuccessPage({ navigate }) {
  const [count, setCount] = useState(0)
  useEffect(() => {
    let val = 0
    const interval = setInterval(() => {
      val += Math.ceil((18247 - val) / 20)
      if (val >= 18248) { setCount(18248); clearInterval(interval) } else setCount(val)
    }, 40)
    return () => clearInterval(interval)
  }, [])

  return (
    <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '80px 24px', position: 'relative', overflow: 'hidden', background: 'radial-gradient(ellipse 80% 60% at 50% 30%, #0F2544 0%, #060D1A 70%)' }}>
      <ParticleField density={60} />
      <div style={{ maxWidth: 480, width: '100%', textAlign: 'center', position: 'relative', zIndex: 2 }} className="fade-up">
        <div style={{ width: 96, height: 96, borderRadius: '50%', margin: '0 auto 30px', background: 'linear-gradient(135deg,var(--emerald),#059669)', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 0 0 10px rgba(16,185,129,0.14), 0 0 0 20px rgba(16,185,129,0.06)' }}>
          <CheckCircle2 size={44} color="#fff" />
        </div>
        <div className="eyebrow" style={{ marginBottom: 18 }}><span className="dot" />Application Received</div>
        <h1 className="headline h1" style={{ color: '#fff', marginBottom: 16, fontSize: 'clamp(30px,5vw,44px)' }}>Thank you</h1>
        <p style={{ fontSize: 15.5, color: '#dbe6f5', marginBottom: 10 }}>You've joined the Airis Early Access Program.</p>
        <p className="lede" style={{ marginBottom: 30 }}>We'll email you with launch updates and your exclusive 30% early access discount when we're ready to ship.</p>

        <div className="glass-panel" style={{ borderRadius: 20, padding: 26, marginBottom: 30 }}>
          <div className="df grad-text" style={{ fontWeight: 700, fontSize: 34 }}>{count.toLocaleString()}+</div>
          <div style={{ fontSize: 13, color: 'var(--muted)', marginTop: 2 }}>people ahead of you on the waitlist</div>
          <div className="mono" style={{ display: 'inline-block', fontSize: 10.5, color: 'var(--cyan)', background: 'rgba(56,189,248,0.1)', padding: '5px 12px', borderRadius: 999, marginTop: 12 }}>TOP 3% OF APPLICANTS</div>
        </div>

        <div style={{ display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap' }}>
          <button className="btn btn-primary" onClick={() => navigate('home')}>Return Home</button>
          <button className="btn btn-ghost" onClick={() => navigate('features')}>Explore Features</button>
        </div>

        <div style={{ marginTop: 44, paddingTop: 30, borderTop: '1px solid var(--hair)' }}>
          <p style={{ fontSize: 12.5, color: 'var(--muted)', marginBottom: 14 }}>Share Airis with your network</p>
          <div style={{ display: 'flex', justifyContent: 'center', gap: 10 }}>
            {[Twitter, Linkedin, Facebook].map((Icon, i) => (
              <button key={i} style={{ width: 38, height: 38, borderRadius: '50%', background: 'rgba(255,255,255,0.06)', border: '1px solid var(--hair)', color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}><Icon size={15} /></button>
            ))}
          </div>
        </div>
      </div>
    </div>
  )
}

// ============================================================================
// ROOT
// ============================================================================
export default function App() {
  const [page, setPage] = useState('home')

  const navigate = (p) => {
    setPage(p)
    window.scrollTo({ top: 0, behavior: 'smooth' })
  }

  return (
    <div className="airis-root">
      <style>{TOKENS}</style>

      {page !== 'success' && <Nav current={page} navigate={navigate} />}

      {page === 'home' && <HomePage navigate={navigate} />}
      {page === 'features' && <FeaturesPage navigate={navigate} />}
      {page === 'technology' && <TechnologyPage navigate={navigate} />}
      {page === 'about' && <AboutPage navigate={navigate} />}
      {page === 'faq' && <FAQPage />}
      {page === 'contact' && <ContactPage />}
      {page === 'waitlist' && <WaitlistPage navigate={navigate} />}
      {page === 'success' && <SuccessPage navigate={navigate} />}

      {page !== 'success' && <Footer navigate={navigate} />}
    </div>
  )
}
